interface FullUser {
  id: number;
  name: string;
  email: string;
  address: string;
  passwordHash: string;
}

// We ONLY want name and email for the frontend
type PublicUser = Pick<FullUser, "name" | "email">;

const user: PublicUser = {
  name: "Alice",
  email: "alice@test.com"
  // Cannot add 'address' or 'id' here!
};

// We want EVERYTHING from FullUser EXCEPT the passwordHash
type SafeUser = Omit<FullUser, "passwordHash">;

const safe: SafeUser = {
  id: 1,
  name: "Bob",
  email: "bob@test.com",
  address: "123 Main St"
};
